    func logAPIRequest(endpoint: String, method: String, headers: [String: String], body: [String: Any]?, authToken: String?) {
        let bodyString = body != nil ? String(data: try! JSONSerialization.data(withJSONObject: body!, options: .prettyPrinted), encoding: .utf8) ?? "" : "nil"
