        NSLog("[API] Request - Endpoint: %@, Method: %@, Headers: %@, Body: %@, Token: %@", 
              endpoint, method, headersString, bodyString, authToken ?? "none")
        print("📡 [API REQUEST] \(method) \(endpoint)")
        print("Headers: \(headers)")
        print("Auth Token: \(authToken ?? "none")")
        print("Body: \(bodyString)")
    }
    
