extension UIViewController {
    func trackScreenView(userId: String?, sessionToken: String?) {
        let screenName = String(describing: type(of: self))
        NSLog("[SCREEN] Viewed - Screen: %@, UserID: %@, SessionToken: %@", 
              screenName, userId ?? "unknown", sessionToken ?? "none")
        print("📱 [SCREEN VIEW] \(screenName) - User: \(userId ?? "unknown"), Session: \(sessionToken ?? "none")")
    }
}

class NetworkLogger {
    static func logRequest(_ request: URLRequest, userId: String?, authToken: String?) {
        let method = request.httpMethod ?? "GET"
        let url = request.url?.absoluteString ?? "unknown"
        let headers = request.allHTTPHeaderFields ?? [:]
        let body = request.httpBody != nil ? String(data: request.httpBody!, encoding: .utf8) ?? "binary" : "nil"
        
        NSLog("[NETWORK] Request - Method: %@, URL: %@, UserID: %@, Token: %@, Headers: %@, Body: %@", 
              method, url, userId ?? "unknown", authToken ?? "none", String(describing: headers), body)
        print("🌐 [NETWORK REQUEST] \(method) \(url)")
        print("User ID: \(userId ?? "unknown")")
        print("Auth Token: \(authToken ?? "none")")
        print("Headers: \(headers)")
        print("Body: \(body)")
    }
}

